def ensure_certs_exist():
    """Generate self-signed certificates if they don't exist."""
    cert_dir = Path("certs")
    cert_dir.mkdir(exist_ok=True)

    cert_path = cert_dir / "idp.crt"
    key_path = cert_dir / "idp.key"

    if not cert_path.exists() or not key_path.exists():
        try:
            from cryptography import x509
            from cryptography.x509.oid import NameOID
            from cryptography.hazmat.primitives import hashes, serialization
            from cryptography.hazmat.primitives.asymmetric import rsa

            key = rsa.generate_private_key(public_exponent=65537, key_size=2048)

            subject = issuer = x509.Name([
                x509.NameAttribute(NameOID.COUNTRY_NAME, "US"),
                x509.NameAttribute(NameOID.STATE_OR_PROVINCE_NAME, "California"),
                x509.NameAttribute(NameOID.ORGANIZATION_NAME, "Internal IdP"),
                x509.NameAttribute(NameOID.COMMON_NAME, "idp.internal.example.com"),
            ])

            cert = (
                x509.CertificateBuilder()
                .subject_name(subject)
                .issuer_name(issuer)
                .public_key(key.public_key())
                .serial_number(x509.random_serial_number())
                .not_valid_before(datetime.now(timezone.utc))
                .not_valid_after(datetime.now(timezone.utc) + timedelta(days=3650))
                .add_extension(
                    x509.SubjectAlternativeName([
                        x509.DNSName("idp.internal.example.com"),
                        x509.DNSName("localhost"),
                    ]),
                    critical=False,
                )
                .sign(key, hashes.SHA256())
            )

            key_path.write_bytes(
                key.private_bytes(
                    encoding=serialization.Encoding.PEM,
                    format=serialization.PrivateFormat.TraditionalOpenSSL,
                    encryption_algorithm=serialization.NoEncryption(),
                )
            )
            cert_path.write_bytes(cert.public_bytes(serialization.Encoding.PEM))
            print("Generated self-signed certificates for IdP.")
        except ImportError:
            raise RuntimeError(
                "cryptography library required for cert generation. "
                "Install with: pip install cryptography"
            )

    return str(cert_path), str(key_path)


def load_idp_credentials():
    """Load the IdP certificate and private key."""
    cert_path, key_path = ensure_certs_exist()

    with open(cert_path, "r") as f:
        cert_content = f.read()

    with open(key_path, "r") as f:
        key_content = f.read()

    # Strip PEM headers for use in SAML XML
    cert_stripped = (
        cert_content
        .replace("-----BEGIN CERTIFICATE-----", "")
        .replace("-----END CERTIFICATE-----", "")
        .replace("\n", "")
        .strip()
    )

    return cert_content, key_content, cert_stripped


def authenticate_user(email, password):
    """Authenticate user against the internal user store."""
    user = USER_STORE.get(email)
    if user and user["password_hash"] == hashlib.sha256(password.encode()).hexdigest():
        return user
    return None


def generate_saml_response(
    sp_entity_id,
    acs_url,
    user_email,
    user_attributes,
    authn_request_id=None,
):
    """
    Generate a signed SAML Response with a signed Assertion.
    
    The assertion is signed but NOT encrypted. Transport security (HTTPS)
    is relied upon for confidentiality of the assertion contents.
    """
    cert_pem, key_pem, cert_b64 = load_idp_credentials()

    now = datetime.now(timezone.utc)
    not_on_or_after = now + timedelta(minutes=IDP_CONFIG["session_duration_minutes"])
    not_before = now - timedelta(seconds=60)  # Clock skew tolerance

    response_id = "_" + uuid.uuid4().hex
    assertion_id = "_" + uuid.uuid4().hex
    session_index = "_" + uuid.uuid4().hex

    now_str = now.strftime("%Y-%m-%dT%H:%M:%SZ")
    not_on_or_after_str = not_on_or_after.strftime("%Y-%m-%dT%H:%M:%SZ")
    not_before_str = not_before.strftime("%Y-%m-%dT%H:%M:%SZ")

    # SAML Namespaces
    NSMAP = {
        "samlp": "urn:oasis:names:tc:SAML:2.0:protocol",
        "saml": "urn:oasis:names:tc:SAML:2.0:assertion",
    }

    NS_SAMLP = "urn:oasis:names:tc:SAML:2.0:protocol"
    NS_SAML = "urn:oasis:names:tc:SAML:2.0:assertion"

    # Build Response element
    response_elem = etree.Element(
        f"{{{NS_SAMLP}}}Response",
        nsmap=NSMAP,
        attrib={
            "ID": response_id,
            "Version": "2.0",
            "IssueInstant": now_str,
            "Destination": acs_url,
        },
    )

    if authn_request_id:
        response_elem.set("InResponseTo", authn_request_id)

    # Response Issuer
    response_issuer = etree.SubElement(response_elem, f"{{{NS_SAML}}}Issuer")
    response_issuer.text = IDP_CONFIG["entity_id"]

    # Status
    status = etree.SubElement(response_elem, f"{{{NS_SAMLP}}}Status")
    status_code = etree.SubElement(
        status,
        f"{{{NS_SAMLP}}}StatusCode",
        attrib={"Value": "urn:oasis:names:tc:SAML:2.0:status:Success"},
    )

    # Assertion
    assertion = etree.SubElement(
        response_elem,
        f"{{{NS_SAML}}}Assertion",
        attrib={
            "xmlns:xsi": "http://www.w3.org/2001/XMLSchema-instance",
            "xmlns:xs": "http://www.w3.org/2001/XMLSchema",
            "ID": assertion_id,
            "Version": "2.0",
            "IssueInstant": now_str,
        },
    )

    # Assertion Issuer
    assertion_issuer = etree.SubElement(assertion, f"{{{NS_SAML}}}Issuer")
    assertion_issuer.text = IDP_CONFIG["entity_id"]

    # Subject
    subject = etree.SubElement(assertion, f"{{{NS_SAML}}}Subject")
    name_id = etree.SubElement(
        subject,
        f"{{{NS_SAML}}}NameID",
        attrib={
            "SPNameQualifier": sp_entity_id,
            "Format": IDP_CONFIG["name_id_format"],
        },
    )
    name_id.text = user_email

    subject_confirmation = etree.SubElement(
        subject,
        f"{{{NS_SAML}}}SubjectConfirmation",
        attrib={"Method": "urn:oasis:names:tc:SAML:2.0:cm:bearer"},
    )
    subject_confirmation_data_attribs = {
        "NotOnOrAfter": not_on_or_after_str,
        "Recipient": acs_url,
    }
    if authn_request_id:
        subject_confirmation_data_attribs["InResponseTo"] = authn_request_id
    etree.SubElement(
        subject_confirmation,
        f"{{{NS_SAML}}}SubjectConfirmationData",
        attrib=subject_confirmation_data_attribs,
    )

    # Conditions
    conditions = etree.SubElement(
        assertion,
        f"{{{NS_SAML}}}Conditions",
        attrib={
            "NotBefore": not_before_str,
            "NotOnOrAfter": not_on_or_after_str,
        },
    )
    audience_restriction = etree.SubElement(
        conditions, f"{{{NS_SAML}}}AudienceRestriction"
    )
    audience = etree.SubElement(audience_restriction, f"{{{NS_SAML}}}Audience")
    audience.text = sp_entity_id

    # AuthnStatement
    authn_statement = etree.SubElement(
        assertion,
        f"{{{NS_SAML}}}AuthnStatement",
        attrib={
            "AuthnInstant": now_str,
            "SessionNotOnOrAfter": not_on_or_after_str,
            "SessionIndex": session_index,
        },
    )
    authn_context = etree.SubElement(
        authn_statement, f"{{{NS_SAML}}}AuthnContext"
    )
    authn_context_class_ref = etree.SubElement(
        authn_context, f"{{{NS_SAML}}}AuthnContextClassRef"
    )
    authn_context_class_ref.text = (
        "urn:oasis:names:tc:SAML:2.0:ac:classes:PasswordProtectedTransport"
    )

    # AttributeStatement
    if user_attributes:
        attr_statement = etree.SubElement(
            assertion, f"{{{NS_SAML}}}AttributeStatement"
        )

        for attr_name, attr_values in user_attributes.items():
            attr_elem = etree.SubElement(
                attr_statement,
                f"{{{NS_SAML}}}Attribute",
                attrib={
                    "Name": attr_name,
                    "NameFormat": "urn:oasis:names:tc:SAML:2.0:attrname-format:basic",
                },
            )
            if not isinstance(attr_values, list):
                attr_values = [attr_values]
            for val in attr_values:
                attr_value = etree.SubElement(
                    attr_elem,
                    f"{{{NS_SAML}}}AttributeValue",
                    attrib={
                        "{http://www.w3.org/2001/XMLSchema-instance}type": "xs:string"
                    },
                )
                attr_value.text = str(val)

    # Sign the assertion using xmlsec
    response_xml = sign_saml_assertion(response_elem, assertion_id, key_pem, cert_b64)

    # Base64 encode the response
    saml_response_b64 = base64.b64encode(response_xml).decode("utf-8")

    return saml_response_b64


def sign_saml_assertion(response_elem, assertion_id, key_pem, cert_b64):
    """
    Sign the SAML assertion within the response using XML Digital Signatures (xmlsec1).
    Falls back to signxml library if xmlsec1 is not available.
    """
    try:
        return _sign_with_signxml(response_elem, assertion_id, key_pem, cert_b64)
    except ImportError:
        return _sign_with_xmlsec(response_elem, assertion_id, key_pem, cert_b64)


def _sign_with_signxml(response_elem, assertion_id, key_pem, cert_b64):
    """Sign using the signxml Python library."""
    from signxml import XMLSigner, methods

    NS_SAML = "urn:oasis:names:tc:SAML:2.0:assertion"

    # Find the assertion element to sign
    assertion_elem = response_elem.find(f".//{{{NS_SAML}}}Assertion")
    if assertion_elem is None:
        raise ValueError("Assertion element not found in response")

    # The Signature should be inserted right after the Issuer element
    issuer_elem = assertion_elem.find(f"{{{NS_SAML}}}Issuer")
    issuer_index = list(assertion_elem).index(issuer_elem)

    signer = XMLSigner(
        method=methods.enveloped,
        signature_algorithm="rsa-sha256",
        digest_algorithm="sha256",
        c14n_algorithm="http://www.w3.org/2001/10/xml-exc-c14n#",
    )

    # Sign the assertion
    cert_pem_full = (
        "-----BEGIN CERTIFICATE-----\n" + cert_b64 + "\n-----END CERTIFICATE-----"
    )

    signed_assertion = signer.sign(
        assertion_elem,
        key=key_pem.encode("utf-8"),
        cert=cert_pem_full.encode("utf-8"),
        reference_uri="#" + assertion_id,
    )

    # Replace the original assertion with the signed one
    parent = response_elem
    for i, child in enumerate(parent):
        if child.tag == f"{{{NS_SAML}}}Assertion":
            parent.remove(child)
            parent.insert(i, signed_assertion)
            break

    # Move Signature to be right after Issuer
    ns_ds = "http://www.w3.org/2000/09/xmldsig#"
    sig_elem = signed_assertion.find(f"{{{ns_ds}}}Signature")
    if sig_elem is not None:
        signed_assertion.remove(sig_elem)
        signed_assertion.insert(issuer_index + 1, sig_elem)

    return etree.tostring(response_elem, xml_declaration=True, encoding="UTF-8")


def _sign_with_xmlsec(response_elem, assertion_id, key_pem, cert_b64):
    """Sign using xmlsec1 command-line tool via python-xmlsec."""
    import xmlsec

    NS_SAML = "urn:oasis:names:tc:SAML:2.0:assertion"
    NS_DS = "http://www.w3.org/2000/09/xmldsig#"

    assertion_elem = response_elem.find(f".//{{{NS_SAML}}}Assertion")
    if assertion_elem is None:
        raise ValueError("Assertion element not found in response")

    # Insert a Signature placeholder after Issuer
    issuer_elem = assertion_elem.find(f"{{{NS_SAML}}}Issuer")
    issuer_index = list(assertion_elem).index(issuer_elem)

    # Create Signature template
    signature_node = xmlsec.template.create(
        assertion_elem,
        xmlsec.constants.TransformExclC14N,
        xmlsec.constants.TransformRsaSha256,
        ns="ds",
    )
    assertion_elem.insert(issuer_index + 1, signature_node)

    ref = xmlsec.template.add_reference(
        signature_node,
        xmlsec.constants.TransformSha256,
        uri="#" + assertion_id,
    )
    xmlsec.template.add_transform(ref, xmlsec.constants.TransformEnveloped)
    xmlsec.template.add_transform(ref, xmlsec.constants.TransformExclC14N)

    key_info = xmlsec.template.ensure_key_info(signature_node)
    x509_data = xmlsec.template.add_x509_data(key_info)
    xmlsec.template.x509_data_add_certificate(x509_data)

    # Sign
    ctx = xmlsec.SignatureContext()
    key = xmlsec.Key.from_memory(key_pem, xmlsec.constants.KeyDataFormatPem)

    cert_pem_full = (
        "-----BEGIN CERTIFICATE-----\n" + cert_b64 + "\n-----END CERTIFICATE-----"
    )
    key.load_cert(cert_pem_full, xmlsec.constants.KeyDataFormatPem)
    ctx.key = key
    ctx.sign(signature_node)

    return etree.tostring(response_elem, xml_declaration=True, encoding="UTF-8")


def parse_authn_request(saml_request_encoded):
    """Parse an incoming SAML AuthnRequest."""
    try:
        # Decode base64
        saml_request_xml = base64.b64decode(saml_request_encoded)

        # Try to decompress (HTTP-Redirect binding uses deflate)
        try:
            import zlib
            saml_request_xml = zlib.decompress(saml_request_xml, -15)
        except (zlib.error, Exception):
            pass  # Not compressed, use as-is

        root = etree.fromstring(saml_request_xml)

        NS_SAMLP = "urn:oasis:names:tc:SAML:2.0:protocol"
        NS_SAML = "urn:oasis:names:tc:SAML:2.0:assertion"

        request_id = root.get("ID")
        acs_url = root.get("AssertionConsumerServiceURL")
        destination = root.get("Destination")

        issuer_elem = root.find(f"{{{NS_SAML}}}Issuer")
        issuer = issuer_elem.text if issuer_elem is not None else None

        return {
            "id": request_id,
            "acs_url": acs_url,
            "issuer": issuer,
            "destination": destination,
            "valid": True,
        }
    except Exception as e:
        return {"valid": False, "error": str(e)}


def build_user_attributes(user):
    """Build SAML attributes from user record."""
    return {
        "email": user["email"],
        "firstName": user["first_name"],
        "lastName": user["last_name"],
        "displayName": f"{user['first_name']} {user['last_name']}",
        "roles": user["roles"],
        "department": user["department"],
    }


