@app.before_request
def require_https():
    """Enforce HTTPS for all requests (except health check)."""
    if request.path == "/health":
        return None
    # In production behind a load balancer, check X-Forwarded-Proto
    if not request.is_secure and request.headers.get("X-Forwarded-Proto", "http") != "https":
        if request.host not in ("localhost", "127.0.0.1") and "localhost" not in request.host:
            return "HTTPS required", 403


@app.route("/health")
def health():
    """Health check endpoint."""
    return {"status": "healthy", "service": "internal-idp"}, 200


@app.route("/sso", methods=["GET", "POST"])
def single_sign_on():
    """
    SSO endpoint - handles both the login form display and authentication.
    Supports HTTP-Redirect (GET) and HTTP-POST (POST) bindings for AuthnRequest.
    """
    if request.method == "GET":
        # SP-initiated SSO: parse the AuthnRequest from query params
        saml_request = request.args.get("SAMLRequest")
        relay_state = request.args.get("RelayState", "")
        sp_entity_id = None
        sp_name = None

        if saml_request:
            authn_req = parse_authn_request(saml_request)
            if authn_req.get("valid"):
                sp_entity_id = authn_req.get("issuer")
                sp_info = SP_REGISTRY.get(sp_entity_id, {})
                sp_name = sp_info.get("name", sp_entity_id)

        return render_template_string(
            LOGIN_TEMPLATE,
            saml_request=saml_request or "",
            relay_state=relay_state,
            sp_entity_id=sp_entity_id or "",
            sp_name=sp_name,
            error=None,
        )

    # POST - process login
    email = request.form.get("email", "").strip().lower()
    password = request.form.get("password", "")
    saml_request = request.form.get("SAMLRequest", "")
    relay_state = request.form.get("RelayState", "")
    sp_entity_id = request.form.get("sp_entity_id", "")

    # Authenticate
    user = authenticate_user(email, password)
    if not user:
        return render_template_string(
            LOGIN_TEMPLATE,
            saml_request=saml_request,
            relay_state=relay_state,
            sp_entity_id=sp_entity_id,
            sp_name=SP_REGISTRY.get(sp_entity_id, {}).get("name"),
            error="Invalid email or password.",
        ), 401

    # Store session
    session["user_email"] = email
    session["authenticated"] = True
    session["auth_time"] = datetime.now(timezone.utc).isoformat()

    # Parse AuthnRequest if present
    authn_request_id = None
    acs_url = None

    if saml_request:
        authn_req = parse_authn_request(saml_request)
        if authn_req.get("valid"):
            authn_request_id = authn_req.get("id")
            sp_entity_id = authn_req.get("issuer") or sp_entity_id
            acs_url = authn_req.get("acs_url")

    # Look up SP configuration
    sp_config = SP_REGISTRY.get(sp_entity_id)
    if not sp_config:
        return f"Unknown Service Provider: {sp_entity_id}", 400

    if not acs_url:
        acs_url = sp_config["acs_url"]

    # Validate ACS URL matches registered SP
    if acs_url != sp_config["acs_url"]:
        return "ACS URL mismatch with registered Service Provider", 400

    # Build user attributes
    user_attributes = build_user_attributes(user)

    # Generate signed SAML Response (assertion is signed, NOT encrypted)
    # Transport security via HTTPS provides confidentiality
    saml_response_b64 = generate_saml_response(
        sp_entity_id=sp_entity_id,
        acs_url=acs_url,
        user_email=email,
        user_attributes=user_attributes,
        authn_request_id=authn_request_id,
    )

    # Return POST binding auto-submit form
    return render_template_string(
        POST_BINDING_TEMPLATE,
        acs_url=acs_url,
        saml_response=saml_response_b64,
        relay_state=relay_state,
    )


@app.route("/idp-initiated", methods=["GET"])
def idp_initiated_sso():
    """
    IdP-initiated SSO: user selects an application to log into.
    """
    sp_entity_id = request.args.get("sp")

    if not session.get("authenticated"):
        # Redirect to login first
        return redirect(f"/sso?sp_entity_id={sp_entity_id or ''}")

    if not sp_entity_id or sp_entity_id not in SP_REGISTRY:
        # Show list of available SPs
        sp_list_html = "<h2>Available Applications</h2><ul>"
        for sp_id, sp_info in SP_REGISTRY.items():
            sp_list_html += (
                f'<li><a href="/idp-initiated?sp={sp_id}">{sp_info["name"]}</a></li>'
            )
        sp_list_html += "</ul>"
        return sp_list_html

    sp_config = SP_REGISTRY[sp_entity_id]
    user_email = session["user_email"]
    user = USER_STORE.get(user_email)

    if not user:
        return "User not found", 404

    user_attributes = build_user_attributes(user)

    saml_response_b64 = generate_saml_response(
        sp_entity_id=sp_entity_id,
        acs_url=sp_config["acs_url"],
        user_email=user_email,
        user_attributes=user_attributes,
    )

    return render_template_string(
        POST_BINDING_TEMPLATE,
        acs_url=sp_config["acs_url"],
        saml_response=saml_response_b64,
        relay_state="",
    )


@app.route("/slo", methods=["GET", "POST"])
def single_logout():
    """Single Logout endpoint."""
    session.clear()

    relay_state = request.args.get("RelayState") or request.form.get("RelayState")
    if relay_state:
        return redirect(relay_state)

    return """
    <!DOCTYPE html>
    <html>
    <head><title>Logged Out</title></head>
    <body style="font-family: Arial; text-align: center; padding-top: 100px;">
        <h2>You have been logged out.</h2>
        <p><a href="/sso">Log in again</a></p>
    </body>
    </html>
    """


@app.route("/metadata")
def metadata():
    """
    IdP Metadata endpoint - provides SAML metadata for SP configuration.
    """
    _, _, cert_b64 = load_idp_credentials()

    metadata_xml = f"""<?xml version="1.0" encoding="UTF-8"?>
<md:EntityDescriptor xmlns:md="urn:oasis:names:tc:SAML:2.0:metadata"
                     xmlns:ds="http://www.w3.org/2000/09/xmldsig#"
                     entityID="{IDP_CONFIG['entity_id']}">
    <md:IDPSSODescriptor 
        WantAuthnRequestsSigned="false"
        protocolSupportEnumeration="urn:oasis:names:tc:SAML:2.0:protocol">
        
        <md:KeyDescriptor use="signing">
            <ds:KeyInfo>
                <ds:X509Data>
                    <ds:X509Certificate>{cert_b64}</ds:X509Certificate>
                </ds:X509Data>
            </ds:KeyInfo>
        </md:KeyDescriptor>
        
        <md:NameIDFormat>{IDP_CONFIG['name_id_format']}</md:NameIDFormat>
        
        <md:SingleSignOnService 
            Binding="urn:oasis:names:tc:SAML:2.0:bindings:HTTP-Redirect"
            Location="{IDP_CONFIG['sso_url']}"/>
        <md:SingleSignOnService 
            Binding="urn:oasis:names:tc:SAML:2.0:bindings:HTTP-POST"
            Location="{IDP_CONFIG['sso_url']}"/>
        
        <md:SingleLogoutService 
            Binding="urn:oasis:names:tc:SAML:2.0:bindings:HTTP-Redirect"
            Location="{IDP_CONFIG['slo_url']}"/>
    </md:IDPSSODescriptor>
</md:EntityDescriptor>"""

    response = make_response(metadata_xml)
    response.headers["Content-Type"] = "application/xml"
    return response


@app.route("/admin/sp", methods=["GET", "POST"])
def manage_service_providers():
    """Simple admin endpoint to manage registered Service Providers."""
    if not session.get("authenticated"):
        return redirect("/sso")

    user = USER_STORE.get(session.get("user_email", ""))
    if not user or "admin" not in user.get("roles", []):
        return "Forbidden: Admin access required", 403

    if request.method == "POST":
        action = request.form.get("action")
        if action == "add":
            entity_id = request.form.get("entity_id", "").strip()
            acs_url = request.form.get("acs_url", "").strip()
            name = request.form.get("name", "").strip()
            if entity_id and acs_url and name:
                SP_REGISTRY[entity_id] = {
                    "acs_url": acs_url,
                    "entity_id": entity_id,
                    "name": name,
                }
        elif action == "remove":
            entity_id = request.form.get("entity_id", "").strip()
            SP_REGISTRY.pop(entity_id, None)

    sp_list = ""
    for sp_id, sp_info in SP_REGISTRY.items():
        sp_list += f"""
        <tr>
            <td>{sp_info['name']}</td>
            <td>{sp_id}</td>
            <td>{sp_info['acs_url']}</td>
            <td>
                <form method="POST" style="display:inline;">
                    <input type="hidden" name="action" value="remove">
                    <input type="hidden" name="entity_id" value="{sp_id}">
                    <button type="submit">Remove</button>
                </form>
            </td>
        </tr>"""

    return f"""
    <!DOCTYPE html>
    <html>
    <head><title>SP Management</title>
    <style>
        body {{ font-family: Arial; padding: 20px; }}
        table {{ border-collapse: collapse; width: 100%; margin: 20px 0; }}
        th, td {{ border: 1px solid #ddd; padding: 12px; text-align: left; }}
        th {{ background: #4CAF50; color: white; }}
        input[type="text"], input[type="url"] {{ padding: 8px; width: 300px; }}
    </style>
    </head>
    <body>
        <h2>Service Provider Management</h2>
        <table>
            <tr><th>Name</th><th>Entity ID</th><th>ACS URL</th><th>Actions</th></tr>
            {sp_list}
        </table>
        <h3>Register New SP</h3>
        <form method="POST">
            <input type="hidden" name="action" value="add">
            <p><label>Name: <input type="text" name="name" required></label></p>
            <p><label>Entity ID: <input type="url" name="entity_id" required></label></p>
            <p><label>ACS URL: <input type="url" name="acs_url" required></label></p>
            <button type="submit">Register SP</button>
        </form>
        <p><a href="/slo">Logout</a></p>
    </body>
    </html>
    """


def create_ssl_context():
    """Create SSL context for HTTPS."""
    cert_path, key_path = ensure_certs_exist()
    context = ssl.SSLContext(ssl.PROTOCOL_TLS_SERVER)
    context.minimum_version = ssl.TLSVersion.TLSv1_2
    context.load_cert_chain(cert_path, key_path)
    return context


